    current := make([]rune, 0)
    for _, raw := range strings.ToLower(text) {
        if unicode.IsLetter(raw) || unicode.IsDigit(raw) {
            current = append(current, raw)
        } else if len(current) > 0 {
            parts = append(parts, string(current))
            current = current[:0]
        }
    }
    if len(current) > 0 {
        parts = append(parts, string(current))
    }
    return strings.Join(parts, "/")
