#include <algorithm>
#include <map>
#include <sstream>
#include <string>
#include <vector>
using namespace std;
int inventory_total_008(const vector<string>& events) {
    map<string, int> inventory;
    for (const string& event : events) {
        stringstream stream(event);
        string action;
        string item;
        int count = 0;
        if (!(stream >> action >> item >> count)) continue;
        if (count < 0) continue;
        if (action == "add") inventory[item] += count;
        else if (action == "remove") inventory[item] = max(0, inventory[item] - count);
    }
    int total = 0;
    for (const auto& item : inventory) total += item.second;
    return total;
}

