#include <algorithm>
#include <map>
#include <string>
using namespace std;
string normalize_query_013(string query) {
    replace(query.begin(), query.end(), ';', '&');
    map<string, string> latest;
    size_t start = 0;
    while (start <= query.size()) {
        size_t end = query.find('&', start);
        string part = query.substr(start, end == string::npos ? string::npos : end - start);
        size_t pos = part.find('=');
        if (pos != string::npos) {
            string key = part.substr(0, pos);
            string value = part.substr(pos + 1);
            transform(key.begin(), key.end(), key.begin(), ::tolower);
            transform(value.begin(), value.end(), value.begin(), ::tolower);
            if (!key.empty() && !value.empty()) latest[key] = value;
        }
        if (end == string::npos) break;
        start = end + 1;
    }
    string out;
    for (const auto& item : latest) {
        if (!out.empty()) out += "&";
        out += item.first + "=" + item.second;
    }
    return out;
}

